#include <iostream>
#include <vector>
#include <string>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    int w;
    cin >> w;

    // board[r][c] = true if mine, indices 1..n, 1..m
    vector<vector<bool>> mine(n + 2, vector<bool>(m + 2, false));

    for (int i = 0; i < w; i++) {
        int r, c;
        cin >> r >> c;
        mine[r][c] = true;
    }

    // 8 directions
    int dr[8] = {-1, -1, -1, 0, 0, 1, 1, 1};
    int dc[8] = {-1, 0, 1, -1, 1, -1, 0, 1};

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (j > 1) cout << ' ';
            if (mine[i][j]) {
                cout << '*';
            } else {
                int cnt = 0;
                for (int d = 0; d < 8; d++) {
                    int ni = i + dr[d];
                    int nj = j + dc[d];
                    if (mine[ni][nj]) cnt++;
                }
                cout << cnt;
            }
        }
        cout << '\n';
    }

    return 0;
}
